        data: {"result": {"minY": 5.0, "minX": 0.0, "maxY": 2000.0, "series": [{"data": [[0.0, 1013.0], [600.0, 34.0], [700.0, 32.0], [200.0, 7.0], [800.0, 69.0], [900.0, 34.0], [1000.0, 63.0], [1100.0, 66.0], [300.0, 12.0], [1200.0, 35.0], [1300.0, 88.0], [1400.0, 127.0], [1500.0, 61.0], [100.0, 12.0], [400.0, 20.0], [1600.0, 26.0], [1700.0, 5.0], [1800.0, 52.0], [1900.0, 173.0], [500.0, 26.0], [2000.0, 45.0]], "isOverall": false, "label": "GET/All heroes", "isController": false}, {"data": [[0.0, 2000.0]], "isOverall": false, "label": "POST/Create a hero with random names", "isController": false}, {"data": [[0.0, 2000.0]], "isOverall": false, "label": "GET/Hero by ID", "isController": false}, {"data": [[0.0, 2000.0]], "isOverall": false, "label": "PUT/Change hero", "isController": false}], "supportsControllersDiscrimination": true, "granularity": 100, "maxX": 2000.0, "title": "Response Time Distribution"}},
